  <tr style="background:#f9fafb;"><td style="padding:12px 16px;font-weight:600;font-size:13px;color:#6b7280;text-transform:uppercase;">${t.similarity}</td><td style="padding:12px 16px;font-size:20px;font-weight:700;color:${statusColor};">${aehnlichkeit}%</td></tr>
  <tr><td style="padding:12px 16px;font-weight:600;font-size:13px;color:#6b7280;text-transform:uppercase;">${t.rating}</td><td style="padding:12px 16px;"><span style="background:${statusColor};color:#fff;padding:4px 12px;border-radius:20px;font-size:13px;font-weight:600;">${statusIcon} ${statusLabel}</span></td></tr>
</table>
<h2 style="font-size:16px;color:#374151;margin-bottom:8px;">${t.assessment}</h2>
<div style="background:#f9fafb;border-left:4px solid ${statusColor};padding:12px 16px;margin-bottom:24px;border-radius:0 6px 6px 0;">
  <p style="margin:0;">${zusammenfassung || t.noSummary}</p>
</div>
<h2 style="font-size:16px;color:#374151;margin-bottom:8px;">📝 ${t.missingH}</h2>
${listItems(fehlende_ueberschriften)}
<h2 style="font-size:16px;color:#374151;margin-bottom:8px;">📌 ${t.gaps}</h2>
${listItems(inhaltliche_luecken)}
<h2 style="font-size:16px;color:#374151;margin-bottom:8px;">✅ ${t.strengths}</h2>
${listItems(staerken)}
${spreadsheet_url ? `<div style="text-align:center;margin-top:32px;"><a href="${spreadsheet_url}" style="background:#3b82f6;color:#fff;padding:12px 28px;border-radius:8px;text-decoration:none;font-weight:600;font-size:15px;">📊 ${t.openReport}</a></div>` : ''}
<p style="text-align:center;margin-top:32px;color:#9ca3af;font-size:12px;">${t.footer}</p>
</body></html>`;

// Subject line in content_sprache (EN for US/GB)
const subjectSimilarityLabel = isEN ? 'Similarity' : t.similarity;
const email_subject = `SEO Audit: ${keyword} | ${aehnlichkeit}% ${subjectSimilarityLabel}`;

return [{
  json: {
    email_empfaenger,
    email_subject,
    email_body: emailBody,
    aehnlichkeit,
    status,
    keyword,
    url,
    spreadsheet_id,
    spreadsheet_url
  }
}];
